"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[27],{2179:(e,a,s)=>{s.r(a),s.d(a,{assets:()=>c,contentTitle:()=>t,default:()=>l,frontMatter:()=>n,metadata:()=>o,toc:()=>d});const o=JSON.parse('{"id":"Documentacao/Sprint01/UX Research/research","title":"Imers\xe3o Preliminar","description":"Imers\xe3o Preliminar","source":"@site/docs/Documentacao/Sprint01/UX Research/research.md","sourceDirName":"Documentacao/Sprint01/UX Research","slug":"/ux-research/imersao-preliminar","permalink":"/ux-research/imersao-preliminar","draft":false,"unlisted":false,"editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/docs/Documentacao/Sprint01/UX Research/research.md","tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"title":"Imers\xe3o Preliminar","slug":"/ux-research/imersao-preliminar","sidebar_position":1},"sidebar":"tutorialSidebar","previous":{"title":"UX Research","permalink":"/ux-research"},"next":{"title":"Personas","permalink":"/ux-research/personas"}}');var i=s(4848),r=s(8453);const n={title:"Imers\xe3o Preliminar",slug:"/ux-research/imersao-preliminar",sidebar_position:1},t=void 0,c={},d=[{value:"Imers\xe3o Preliminar",id:"imers\xe3o-preliminar",level:2},{value:"Os Profissionais, as Responsabilidades e os Desafios",id:"os-profissionais-as-responsabilidades-e-os-desafios",level:3},{value:"Impacto na Rotina e na Seguran\xe7a",id:"impacto-na-rotina-e-na-seguran\xe7a",level:3},{value:"Conclus\xe3o",id:"conclus\xe3o",level:3}];function m(e){const a={h2:"h2",h3:"h3",p:"p",...(0,r.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(a.h2,{id:"imers\xe3o-preliminar",children:"Imers\xe3o Preliminar"}),"\n",(0,i.jsx)(a.p,{children:"A presente etapa de Imers\xe3o Preliminar, parte da pesquisa de UX e das personas, tem como objetivo aprofundar o entendimento sobre a problem\xe1tica da rastreabilidade de medicamentos em ambiente hospitalar no Brasil. A abordagem utilizada \xe9 a pesquisa desk, que consiste na an\xe1lise de dados e informa\xe7\xf5es j\xe1 existentes de fontes secund\xe1rias, como artigos cient\xedficos, relat\xf3rios, dados de conselhos profissionais e conte\xfados online. O foco desta imers\xe3o s\xe3o os profissionais diretamente envolvidos no processo de dispensa\xe7\xe3o e controle de medicamentos: farmac\xeauticos e t\xe9cnicos de farm\xe1cia."}),"\n",(0,i.jsx)(a.h3,{id:"os-profissionais-as-responsabilidades-e-os-desafios",children:"Os Profissionais, as Responsabilidades e os Desafios"}),"\n",(0,i.jsx)(a.p,{children:"Segundo dados do Panorama da Farm\xe1cia Hospitalar no Brasil (CFF, 2022), farmac\xeauticos hospitalares s\xe3o, em sua maioria, mulheres (entre 30 e 45 anos), com gradua\xe7\xe3o em Farm\xe1cia e, frequentemente, com especializa\xe7\xe3o em Farm\xe1cia Hospitalar ou Cl\xednica (Revista Brasileira de Farm\xe1cia Hospitalar e Servi\xe7os de Sa\xfade). Sua experi\xeancia profissional geralmente ultrapassa 5 anos, propiciando um amplo conhecimento dos processos hospitalares. As responsabilidades desses profissionais s\xe3o extensas, incluindo supervis\xe3o da equipe, valida\xe7\xe3o de prescri\xe7\xf5es, garantia da dispensa\xe7\xe3o correta, gest\xe3o de estoque e compras, farmacovigil\xe2ncia, treinamento da equipe e participa\xe7\xe3o em comiss\xf5es (Resolu\xe7\xf5es do CFF)."}),"\n",(0,i.jsx)(a.p,{children:"T\xe9cnicos de farm\xe1cia, por sua vez, apresentam um perfil demogr\xe1fico mais diversificado em g\xeanero, com idade entre 25 e 40 anos e forma\xe7\xe3o t\xe9cnica na \xe1rea (CFF, ICTQ). Suas responsabilidades abrangem a separa\xe7\xe3o e dispensa\xe7\xe3o de medicamentos, organiza\xe7\xe3o e controle de estoque, recebimento e confer\xeancia de medicamentos, e aux\xedlio ao farmac\xeautico (CFF)."}),"\n",(0,i.jsx)(a.p,{children:"Ambos os grupos enfrentam desafios significativos, muitos dos quais exacerbados pela falta de automatiza\xe7\xe3o no rastreamento de medicamentos. Para os farmac\xeauticos, a sobrecarga de trabalho, a press\xe3o por resultados, a necessidade de atualiza\xe7\xe3o tecnol\xf3gica constante e a busca por reconhecimento profissional s\xe3o recorrentes (Revista Brasileira de Farm\xe1cia Hospitalar e Servi\xe7os de Sa\xfade). A aus\xeancia de um sistema eficiente de rastreio intensifica esses problemas, gerando processos manuais, aumentando o risco de erros de medica\xe7\xe3o e dificultando o controle de estoque e validade."}),"\n",(0,i.jsx)(a.p,{children:"A rotina de ambos, farmac\xeauticos e t\xe9cnicos, sem a automatiza\xe7\xe3o, \xe9 marcada por tarefas manuais e repetitivas, como confer\xeancia visual de etiquetas, registros em planilhas ou sistemas pouco integrados e contagens f\xedsicas de estoque. A percep\xe7\xe3o sobre sistemas manuais de rastreamento \xe9 negativa, devido \xe0 inefici\xeancia, ao risco de erros e \xe0 dificuldade em obter informa\xe7\xf5es precisas."}),"\n",(0,i.jsx)(a.p,{children:"T\xe9cnicos de farm\xe1cia, especificamente, relatam em f\xf3runs online e artigos sobre a pr\xe1tica da profiss\xe3o, dores como a repetitividade das tarefas de confer\xeancia manual, o risco de erros na dispensa\xe7\xe3o (especialmente em ambientes de alta demanda) e a dificuldade em lidar com informa\xe7\xf5es descentralizadas."}),"\n",(0,i.jsx)(a.h3,{id:"impacto-na-rotina-e-na-seguran\xe7a",children:"Impacto na Rotina e na Seguran\xe7a"}),"\n",(0,i.jsx)(a.p,{children:"A falta de automatiza\xe7\xe3o no rastreamento de medicamentos em hospitais brasileiros emerge como um problema central, com impactos diretos na rotina, na efici\xeancia e, crucialmente, na seguran\xe7a do paciente. Processos manuais de rastreamento s\xe3o inerentemente mais propensos a erros, desde a separa\xe7\xe3o e dispensa\xe7\xe3o at\xe9 o controle de estoque. A dificuldade em obter informa\xe7\xf5es precisas e em tempo real sobre a localiza\xe7\xe3o, validade e lote dos medicamentos compromete a tomada de decis\xf5es e pode levar a falhas na administra\xe7\xe3o, com consequ\xeancias potencialmente graves para os pacientes."}),"\n",(0,i.jsx)(a.p,{children:"A resist\xeancia a mudan\xe7as e \xe0 digitaliza\xe7\xe3o do processo pode existir, tanto entre farmac\xeauticos quanto entre t\xe9cnicos de farm\xe1cia, especialmente entre profissionais com mais tempo de atua\xe7\xe3o ou menor familiaridade com tecnologia. No entanto, a pesquisa desk indica que a aceita\xe7\xe3o de novas tecnologias tende a ser maior quando os benef\xedcios s\xe3o claramente demonstrados, como a redu\xe7\xe3o de erros, a otimiza\xe7\xe3o do tempo e a melhoria da seguran\xe7a do paciente."}),"\n",(0,i.jsx)(a.h3,{id:"conclus\xe3o",children:"Conclus\xe3o"}),"\n",(0,i.jsx)(a.p,{children:"Esta pesquisa desk, como parte da Imers\xe3o Preliminar, revelou um cen\xe1rio desafiador para farmac\xeauticos e t\xe9cnicos de farm\xe1cia em hospitais brasileiros. A falta de automatiza\xe7\xe3o emerge como um fator que contribui para a sobrecarga de trabalho, o risco de erros e a inefici\xeancia dos processos. As informa\xe7\xf5es coletadas nesta etapa fornecem uma base s\xf3lida para as pr\xf3ximas fases da pesquisa de UX, direcionando o foco para as necessidades e dores reais desses profissionais, e permitindo o desenvolvimento de solu\xe7\xf5es que efetivamente contribuam para a melhoria da seguran\xe7a do paciente e da qualidade do servi\xe7o farmac\xeautico hospitalar."})]})}function l(e={}){const{wrapper:a}={...(0,r.R)(),...e.components};return a?(0,i.jsx)(a,{...e,children:(0,i.jsx)(m,{...e})}):m(e)}},8453:(e,a,s)=>{s.d(a,{R:()=>n,x:()=>t});var o=s(6540);const i={},r=o.createContext(i);function n(e){const a=o.useContext(r);return o.useMemo((function(){return"function"==typeof e?e(a):{...a,...e}}),[a,e])}function t(e){let a;return a=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:n(e.components),o.createElement(r.Provider,{value:a},e.children)}}}]);